"""Toy 2D dataset — loads per-episode data generated by ``generate_toy_data.py``.

Each episode is a directory with:
    episode.json
    frames/
        000000.png
        000001.png
        ...
"""

from __future__ import annotations

import json
from pathlib import Path
from typing import Any, Callable, Dict, List, Optional, Tuple

import numpy as np
from PIL import Image
from torch.utils.data import Dataset

from mini_vla.datasets.transforms import tokenize


def _find_episode_dirs(root: str | Path) -> List[Path]:
    """Discover all episode directories under ``root/episodes/``."""
    episodes_root = Path(root) / "episodes"
    if not episodes_root.is_dir():
        raise FileNotFoundError(f"Episodes directory not found: {episodes_root}")
    dirs = sorted(
        p for p in episodes_root.iterdir()
        if p.is_dir() and p.name.startswith("ep_")
    )
    if not dirs:
        raise FileNotFoundError(f"No episode directories found in {episodes_root}")
    return dirs


def _load_steps(episode_dir: Path) -> Tuple[Dict[str, Any], List[Dict[str, Any]]]:
    """Load ``episode.json`` and return ``(meta, steps)``."""
    json_path = episode_dir / "episode.json"
    with open(json_path, "r", encoding="utf-8") as f:
        data = json.load(f)
    ep_meta = {
        "episode_id": data["episode_id"],
        "instruction": data["instruction"],
    }
    return ep_meta, data["steps"]


class Toy2DDataset(Dataset):
    """PyTorch Dataset over Toy 2D episodes.

    Each ``__getitem__`` returns a single step (image + instruction + state) with
    its corresponding expert action.

    Args:
        root: Path to the dataset root (e.g. ``data/toy_2d``).
        max_text_len: Maximum token sequence length for instruction text.
        transform: Optional callable applied to the image tensor.
    """

    def __init__(
        self,
        root: str | Path,
        max_text_len: int = 16,
        transform: Optional[Callable] = None,
    ) -> None:
        self.root = Path(root)
        self.max_text_len = max_text_len
        self.transform = transform

        self._episode_dirs = _find_episode_dirs(self.root)

        # Build flat index: (episode_index, step_index)
        self._index: List[Tuple[int, int]] = []
        self._ep_cache: List[Tuple[Dict[str, Any], List[Dict[str, Any]]]] = []

        for ep_idx, ep_dir in enumerate(self._episode_dirs):
            meta, steps = _load_steps(ep_dir)
            self._ep_cache.append((meta, steps))
            for step_idx in range(len(steps)):
                self._index.append((ep_idx, step_idx))

    def __len__(self) -> int:
        return len(self._index)

    def __getitem__(self, idx: int) -> Dict[str, Any]:
        ep_idx, step_idx = self._index[idx]
        meta, steps = self._ep_cache[ep_idx]
        step = steps[step_idx]

        # Load image
        ep_dir = self._episode_dirs[ep_idx]
        img_path = ep_dir / step["frame"]
        img = Image.open(img_path).convert("RGB")
        img_tensor = np.asarray(img, dtype=np.float32) / 255.0  # [H, W, C]
        img_tensor = np.transpose(img_tensor, (2, 0, 1))  # [C, H, W]

        if self.transform is not None:
            img_tensor = self.transform(img_tensor)

        # Tokenize instruction
        input_ids = tokenize(meta["instruction"], max_len=self.max_text_len)

        # State & action
        state = np.array(step["state"], dtype=np.float32)
        action = np.array(step["action"], dtype=np.float32)

        return {
            "image": img_tensor,
            "input_ids": np.array(input_ids, dtype=np.int64),
            "state": state,
            "action": action,
            "instruction": meta["instruction"],
        }


__all__ = [
    "Toy2DDataset",
]
